// ─── REUSABLE UI ──────────────────────────────────────────────────────────────
const Seg = ({ options, selected, onChange }) => (
  <div style={{display:'flex',background:'#e5e5ea',borderRadius:9,padding:2,gap:2}}>
    {options.map(o => (
      <button key={o.value} onClick={() => onChange(o.value)}
        style={{flex:1,padding:'7px 4px',border:'none',borderRadius:7,fontSize:13,fontWeight:500,
          cursor:'pointer',transition:'all .15s',
          background: selected===o.value ? '#fff' : 'none',
          color: selected===o.value ? '#1c1c1e' : '#8e8e93',
          boxShadow: selected===o.value ? '0 1px 3px rgba(0,0,0,.12)' : 'none'}}>
        {o.label}
      </button>
    ))}
  </div>
);

const Btn = ({ children, onClick, color='#007aff', disabled=false, style={} }) => (
  <button onClick={onClick} disabled={disabled}
    style={{width:'100%',padding:'16px',background: disabled ? '#c7c7cc' : color,
      border:'none',borderRadius:14,fontSize:17,fontWeight:600,color:'#fff',
      cursor: disabled ? 'not-allowed' : 'pointer',display:'flex',
      alignItems:'center',justifyContent:'center',gap:8, ...style}}>
    {children}
  </button>
);

